"use client"

import { useState, useMemo, useRef } from "react"
import { useRouter } from "next/navigation"
import Image from "next/image"
import { useExploreHubs } from "@/hooks/useExplore"
import { useMySubscriptions } from "@/hooks/useSubscriptions"
import { useInitializePayment } from "@/hooks/usePayments"
import { useHubPlans } from "@/hooks/usePlans"
import type { HubExploreResponse } from "@/types/hubs"

const cn = (...c: (string | boolean | undefined)[]) => c.filter(Boolean).join(" ")
const HUB_COLORS = ["#8A2BE2", "#6366F1", "#F59E0B", "#10B981", "#EC4899", "#0EA5E9"]
const hubColor = (id: number) => HUB_COLORS[id % HUB_COLORS.length]
const initial = (s: string) => s.charAt(0).toUpperCase()

// ─── Join Button ──────────────────────────────────────────────────────────────
function JoinButton({ hub, isSubscribed }: { hub: HubExploreResponse; isSubscribed: boolean }) {
  const { data: plans = [], isLoading: plansLoading } = useHubPlans(hub.id)
  const { mutate: initPayment, isPending } = useInitializePayment()

  if (isSubscribed) {
    return (
      <span className="text-[12px] font-semibold px-4 py-1.5 rounded-full bg-[#F3E8FF] text-[#8A2BE2]">
        Joined
      </span>
    )
  }

  const cheapestPlan = plans
    .filter(p => p.is_active)
    .sort((a, b) => a.price - b.price)[0]

  return (
    <button
      onClick={() => {
        if (!cheapestPlan) return
        initPayment(
          { plan_id: cheapestPlan.id },
          { onSuccess: (data) => { window.location.href = data.checkout_url } }
        )
      }}
      disabled={isPending || plansLoading || !cheapestPlan}
      className={cn(
        "text-[12px] font-semibold px-4 py-1.5 rounded-full border transition-all",
        "bg-white text-[#2D0052] border-[#EDE5F8] hover:bg-[#8A2BE2] hover:text-white hover:border-[#8A2BE2]",
        (isPending || plansLoading || !cheapestPlan) && "opacity-40 cursor-not-allowed"
      )}
    >
      {isPending ? "…" : cheapestPlan ? `Join · ${cheapestPlan.currency} ${cheapestPlan.price}` : "No plans"}
    </button>
  )
}

// ─── Hub Card ─────────────────────────────────────────────────────────────────
function HubCard({ hub, isSubscribed }: { hub: HubExploreResponse; isSubscribed: boolean }) {
  const router = useRouter()
  const { data: plans = [] } = useHubPlans(hub.id)
  const color = hubColor(hub.id)
  const activePlans = plans.filter(p => p.is_active).sort((a, b) => a.price - b.price)

  return (
    <div
      className="bg-white rounded-2xl border border-[#EDE5F8] overflow-hidden hover:shadow-[0_4px_24px_rgba(138,43,226,0.08)] transition-all cursor-pointer"
      style={{ boxShadow: "0 1px 4px rgba(45,0,82,0.04)" }}
    >
      {/* Banner */}
      <div
        className="relative w-full h-[110px]"
        onClick={() => router.push(`/hubs/${hub.id}`)}
      >
        {hub.banner_url ? (
          <Image src={hub.banner_url} alt="" fill className="object-cover" unoptimized sizes="600px" />
        ) : (
          <div
            className="w-full h-full"
            style={{ background: `linear-gradient(135deg, #2D0052 0%, ${color} 100%)` }}
          >
            <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg" style={{ opacity: 0.15 }}>
              <defs>
                <pattern id={`dots-${hub.id}`} x="0" y="0" width="16" height="16" patternUnits="userSpaceOnUse">
                  <circle cx="1.5" cy="1.5" r="1" fill="white" />
                </pattern>
              </defs>
              <rect width="100%" height="100%" fill={`url(#dots-${hub.id})`} />
            </svg>
          </div>
        )}

        {/* Creator avatar — bigger, Snapchat-style overlap */}
        <div
          className="absolute -bottom-6 left-4 w-[52px] h-[52px] rounded-full border-[3px] border-white overflow-hidden flex items-center justify-center text-white text-[18px] font-bold"
          style={{
            background: hub.avatar_url ? "transparent" : color,
            boxShadow: "0 2px 10px rgba(45,0,82,0.2)",
          }}
        >
          {hub.avatar_url ? (
            <Image src={hub.avatar_url} alt={hub.creator.username} fill className="object-cover" unoptimized />
          ) : (
            initial(hub.creator.username)
          )}
        </div>
      </div>

      {/* Body */}
      <div className="pt-9 px-4 pb-4">
        {/* Name + handle */}
        <div
          className="flex items-start justify-between gap-3 mb-2"
          onClick={() => router.push(`/hubs/${hub.id}`)}
        >
          <div className="min-w-0">
            <div className="flex items-center gap-2">
              <h3 className="text-[14px] font-bold text-[#2D0052] truncate">{hub.name}</h3>
              {isSubscribed && (
                <span className="text-[9.5px] font-bold px-1.5 py-0.5 rounded-full bg-[#F3E8FF] text-[#8A2BE2]">
                  Joined
                </span>
              )}
            </div>
            <p className="text-[11.5px] text-[#A08DBE] mt-0.5">@{hub.creator.username}</p>
          </div>
        </div>

        {hub.description && (
          <p
            className="text-[12.5px] text-[#6B4F8A] leading-relaxed mb-3 line-clamp-2"
            onClick={() => router.push(`/hubs/${hub.id}`)}
          >
            {hub.description}
          </p>
        )}

        {/* Plan tiers */}
        {activePlans.length > 0 && (
          <div className="flex gap-2 mb-3 flex-wrap">
            {activePlans.map(plan => (
              <div
                key={plan.id}
                className="flex items-center gap-1.5 text-[11px] font-semibold px-2.5 py-1 rounded-full border border-[#EDE5F8] bg-[#FBF8FF] text-[#6B4F8A]"
              >
                <span
                  className="w-1.5 h-1.5 rounded-full shrink-0"
                  style={{ background: color }}
                />
                {plan.name}
                <span className="text-[#A08DBE] font-medium">
                  · {plan.currency} {plan.price}/{plan.billing_cycle === "monthly" ? "mo" : plan.billing_cycle === "yearly" ? "yr" : "once"}
                </span>
              </div>
            ))}
          </div>
        )}

        {/* Footer */}
<div className="flex items-center justify-between pt-3 border-t border-[#F5EFFF]">
  <div className="flex items-center gap-3 text-[11px] text-[#A08DBE]">
    <span>{hub.subscriber_count.toLocaleString()} members</span>
    <span className="text-[#D4C5E8]">·</span>
    <span>{hub.content_count} posts</span>
  </div>

  {isSubscribed ? (
    <span className="text-[12px] font-semibold px-4 py-1.5 rounded-full bg-[#F3E8FF] text-[#8A2BE2]">
      Joined
    </span>
  ) : (
    <button
      onClick={() => router.push(`/hubs/${hub.id}?tab=plans`)}
      className="text-[12px] font-semibold px-4 py-1.5 rounded-full border border-[#EDE5F8] bg-white text-[#2D0052] hover:bg-[#8A2BE2] hover:text-white hover:border-[#8A2BE2] transition-all"
    >
      {activePlans.length === 1
        ? `Join · ${activePlans[0].currency} ${activePlans[0].price}`
        : "See plans"}
    </button>
  )}
</div>
      </div>
    </div>
  )
}

// ─── Page ─────────────────────────────────────────────────────────────────────
export default function CommunitiesPage() {
  const router = useRouter()
  const [search, setSearch] = useState("")
  const [debouncedSearch, setDebouncedSearch] = useState("")
  const [sort, setSort] = useState<"newest" | "popular">("newest")
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const handleSearch = (value: string) => {
    setSearch(value)
    if (debounceRef.current) clearTimeout(debounceRef.current)
    debounceRef.current = setTimeout(() => setDebouncedSearch(value), 400)
  }

  const { data: hubs = [], isLoading, isError } = useExploreHubs({
    q: debouncedSearch || undefined,
    sort_by: sort,
    limit: 50,
  })

  const { data: mySubscriptions = [] } = useMySubscriptions()

  const subscribedHubIds = useMemo(
    () => new Set(mySubscriptions.filter(s => s.status === "active").map(s => s.hub.id)),
    [mySubscriptions]
  )

  return (
    <div className="min-h-screen bg-[#FAFAFA]">
      <div className="max-w-[600px] mx-auto px-4 py-7">

        {/* Header */}
        <div className="mb-6">
          <h1 className="text-[22px] font-bold text-[#2D0052]">Communities</h1>
          <p className="text-[13px] text-[#A08DBE] mt-0.5">Find your people. Grow together.</p>
        </div>

        {/* Search + sort */}
        <div className="flex gap-2 mb-5">
          <div className="relative flex-1">
            <svg className="absolute left-3.5 top-1/2 -translate-y-1/2 text-[#C4B5D4]" width="13" height="13" viewBox="0 0 13 13" fill="none" stroke="currentColor" strokeWidth="1.6">
              <circle cx="5.5" cy="5.5" r="4"/><path d="M9 9 12 12" strokeLinecap="round"/>
            </svg>
            <input
              value={search}
              onChange={e => handleSearch(e.target.value)}
              placeholder="Search communities…"
              className="w-full pl-9 pr-4 py-2.5 bg-white border border-[#EDE5F8] rounded-xl text-[13px] text-[#2D0052] placeholder:text-[#C4B5D4] outline-none focus:border-[#8A2BE2] focus:ring-2 focus:ring-[#8A2BE2]/10 transition-all"
            />
          </div>
          <div className="flex gap-1 bg-white border border-[#EDE5F8] rounded-xl p-1">
            {[{ label: "New", value: "newest" as const }, { label: "Popular", value: "popular" as const }].map(opt => (
              <button
                key={opt.value}
                onClick={() => setSort(opt.value)}
                className={cn(
                  "text-[12px] font-semibold px-3 py-1.5 rounded-[8px] transition-all",
                  sort === opt.value
                    ? "bg-[#8A2BE2] text-white"
                    : "text-[#6B4F8A] hover:bg-[#F5EFFF]"
                )}
              >
                {opt.label}
              </button>
            ))}
          </div>
        </div>

        {/* Feed */}
        {isLoading ? (
          <div className="flex flex-col gap-3">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="bg-white rounded-2xl border border-[#EDE5F8] h-[200px] animate-pulse" />
            ))}
          </div>
        ) : isError ? (
          <p className="text-[13px] text-red-400 py-8 text-center">Failed to load. Please try again.</p>
        ) : hubs.length === 0 ? (
          <p className="text-[13px] text-[#A08DBE] py-8 text-center">No communities found.</p>
        ) : (
          <div className="flex flex-col gap-3">
            {hubs.map(hub => (
              <HubCard
                key={hub.id}
                hub={hub}
                isSubscribed={subscribedHubIds.has(hub.id)}
              />
            ))}
          </div>
        )}

      </div>
    </div>
  )
}